const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

let n;
let arr;
let count = 0;
let inputCount = 0;

rl.on('line', (input) => {
    if (inputCount == 0) {
        n = parseInt(input);
    } else {
        arr = input.split(' ').map(Number);
        for (let i = 0; i < n; i++) {
            for (let j = i + 1; j < n; j++) {
                if (gcd(arr[i], arr[j]) == 1) {
                    count++;
                }
            }
        }
        console.log(count);
        rl.close();
    }
    inputCount++;
});

